import java.util.*;

class Solution {
    private static final int MODULO = 1000000007;

    public int countPaths(int n, int[][] roads) {
        List<List<int[]>> adjList = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            adjList.add(new ArrayList<>());
        }

        for (int[] road : roads) {
            adjList.get(road[0]).add(new int[]{road[1], road[2]});
            adjList.get(road[1]).add(new int[]{road[0], road[2]});
        }

        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[0] = 0;
        int[] cnt = new int[n];
        cnt[0] = 1;
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[1]));
        pq.add(new int[]{0, 0});

        while (!pq.isEmpty()) {
            int[] cur = pq.poll();
            int node = cur[0], distance = cur[1];

            if (distance > dist[node]) continue;

            for (int[] neighbor : adjList.get(node)) {
                int nextNode = neighbor[0], edgeDist = neighbor[1];

                if (distance + edgeDist > dist[nextNode]) continue;

                if (distance + edgeDist == dist[nextNode]) {
                    cnt[nextNode] = (cnt[nextNode] + cnt[node]) % MODULO;
                } else {
                    cnt[nextNode] = cnt[node];
                    dist[nextNode] = distance + edgeDist;
                    pq.add(new int[]{nextNode, dist[nextNode]});
                }
            }
        }

        return cnt[n - 1];
    }
}
